prefix bbo: <http://www.onto-bpo.eu/ontologies/bbo#>
prefix bboExt: <http://www.onto-bpo.eu/ontologies/bboExtension#>
prefix rdfs: <http://www.w3.org/2000/01/rdf-schema#>
prefix tai: <https://www.teamingai-project.eu/>
prefix xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT DISTINCT ?model ?modelName ?origId ?normId ?org WHERE {
  ?model a bboExt:Model .
  ?model bbo:name ?modelName .
  OPTIONAL { ?model tai:originalId ?origId . }
  OPTIONAL { ?model tai:normalizedId ?normId . }
  OPTIONAL { ?model tai:belongsTo ?org . }
  FILTER(
    STRENDS(STR(?model), "4e8df28e6d9f4afe970d06522542e830") ||
    (BOUND(?origId) && STRENDS(STR(?origId), "4e8df28e6d9f4afe970d06522542e830")) ||
    (BOUND(?normId) && STRENDS(STR(?normId), "4e8df28e6d9f4afe970d06522542e830"))
  )
}
LIMIT 25

prefix bbo: <http://www.onto-bpo.eu/ontologies/bbo#>
prefix bboExt: <http://www.onto-bpo.eu/ontologies/bboExtension#>
prefix rdfs: <http://www.w3.org/2000/01/rdf-schema#>
prefix tai: <https://www.teamingai-project.eu/>
prefix xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT DISTINCT ?choreo ?choreoName
       (COUNT(DISTINCT ?start) AS ?startCount)
       (COUNT(DISTINCT ?end) AS ?endCount)
       (SUM(IF(?canReachEnd,1,0)) AS ?startsThatCanReachEndCount)
       (COUNT(DISTINCT ?start) - SUM(IF(?canReachEnd,1,0)) AS ?startsThatCannotReachEndCount)
WHERE {
  ?model a bboExt:Model ;
         tai:originalId "4e8df28e6d9f4afe970d06522542e830" .

  ?defs tai:belongsTo ?model .
  ?choreo tai:belongsTo ?defs ;
          a bboExt:Choreography .
  OPTIONAL { ?choreo bbo:name ?choreoName . }

  ?start a bboExt:StartEvent ;
         tai:belongsTo ?choreo .

  OPTIONAL {
    ?end a bboExt:EndEvent ;
         tai:belongsTo ?choreo .
  }

  BIND(
    EXISTS {
      ?start ((^bbo:has_sourceRef)/bbo:has_targetRef)+ ?endReachable .
      ?endReachable tai:belongsTo ?choreo .
      ?endReachable a bboExt:EndEvent .
    } AS ?canReachEnd
  )
}
GROUP BY ?choreo ?choreoName
ORDER BY ?startsThatCannotReachEndCount DESC
LIMIT 25

prefix bbo: <http://www.onto-bpo.eu/ontologies/bbo#>
prefix bboExt: <http://www.onto-bpo.eu/ontologies/bboExtension#>
prefix rdfs: <http://www.w3.org/2000/01/rdf-schema#>
prefix tai: <https://www.teamingai-project.eu/>
prefix xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT DISTINCT ?choreo ?choreoName
       (COUNT(DISTINCT ?start) AS ?startCount)
       (COUNT(DISTINCT ?end) AS ?endCount)
       (SUM(?canReachEndInt) AS ?startsThatCanReachEndCount)
       (COUNT(DISTINCT ?start) - SUM(?canReachEndInt) AS ?startsThatCannotReachEndCount)
WHERE {
  ?model a bboExt:Model ;
         tai:originalId "4e8df28e6d9f4afe970d06522542e830" ;
         tai:belongsTo ?org .

  ?defs tai:belongsTo ?model .
  ?choreo tai:belongsTo ?defs ;
          a bboExt:Choreography .
  OPTIONAL { ?choreo bbo:name ?choreoName . }

  ?start a bboExt:StartEvent ;
         tai:belongsTo ?choreo .

  OPTIONAL {
    ?end a bboExt:EndEvent ;
         tai:belongsTo ?choreo .
  }

  BIND(
    EXISTS {
      ?start ((^bbo:has_sourceRef)/bbo:has_targetRef)+ ?endReachable .
      ?endReachable tai:belongsTo ?choreo .
      ?endReachable a bboExt:EndEvent .
    } AS ?canReachEnd
  )

  BIND(IF(?canReachEnd,1,0) AS ?canReachEndInt)
}
GROUP BY ?choreo ?choreoName
